using Microsoft.ML;
using ChurnPredictor;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "..", "..", "..", "Data", "customers.csv");
IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" string to boolean Label column
var pipeline = mlContext.Transforms.CustomMapping<CustomerData, object>(
        (input, _) => { }, contractName: null) // no-op; Label is already bool via LoadColumn
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(dataView);
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

// --- Endpoints ---
app.MapGet("/", () => "ChurnPredictor API – POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var result = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        churned = result.Churned,
        probability = Math.Round(result.Probability, 4)
    });
});

app.Run();

record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

